SELECT AVG(area_size) 
FROM fishing_areas 
WHERE status IN ('open', 'restricted');

SELECT *
FROM fishing_activity_logs
WHERE user_id = 0 AND activity_type = 'catch';

SELECT area_id, region
FROM fishing_areas
WHERE area_size > 200;

SELECT species 
FROM fishing_areas 
WHERE area_id = 1;

SELECT AVG(duration) AS average_duration
FROM fishing_activity_logs
WHERE approval_status = 'approved';
